import clsx from 'clsx';

import { ChartLegendItem } from './ChartLegendItem/ChartLegendItem.js';
import { legendContent, legendGrid } from './ChartVirtualizedLegendGrid.sty.js';
import { ORIENTATION } from '../../../../constants.js';
import { ChartLegendOrientation } from '../../../../types/legend.js';
import { useChartLayoutRatio } from '../../../chart-layout/hooks/useChartLayoutRatio.js';
import {
  CATEGORICAL_LEGEND_CLASS,
  LEGEND_ACTION_BUTTON_WIDTH,
} from '../constants.js';
import { useLegendGridSettings } from '../context/LegendGridSettingsContext.js';
import { LegendItem } from '../types/legend.js';

interface ChartLegendGridProps {
  /** Items to be represented on the legend grid */
  items: LegendItem[];
  /** orientation of the grid */
  orientation: ChartLegendOrientation;
}

/**
 * Static Grid to represent the legend items, does not use virtualization
 * @param props - Items, gridSettings
 * @returns Grid containing all items positioned
 */
export const ChartLegendGrid = (props: ChartLegendGridProps) => {
  const { items, orientation } = props;
  const { legendRef } = useChartLayoutRatio();
  const {
    maxRows,
    minItemWidth,
    canFitAllItemsWithoutScrollbar,
    maxItemWidth,
  } = useLegendGridSettings();

  const nrOfColumns = Math.ceil(items.length / maxRows);

  const gridTemplateColumns =
    !canFitAllItemsWithoutScrollbar || orientation === ORIENTATION.Horizontal
      ? `repeat(auto-fit, minmax(${
          minItemWidth - LEGEND_ACTION_BUTTON_WIDTH
        }px, 1fr))`
      : `repeat(${nrOfColumns}, minmax(${minItemWidth}px, ${maxItemWidth}px))`;

  return (
    <div className={legendContent({ layout: orientation })}>
      <div
        ref={legendRef}
        data-testid="chart-legend-grid-static"
        className={clsx(
          legendGrid({ layout: orientation }),
          CATEGORICAL_LEGEND_CLASS,
        )}
        style={{ gridTemplateColumns }}
      >
        {items.map((item) => (
          <ChartLegendItem
            key={item.id}
            item={item}
            numberOfItems={items.length}
          />
        ))}
      </div>
    </div>
  );
};

ChartLegendGrid['displayName'] = 'ChartLegendGrid';
